#include <stdio.h>
#include <stdlib.h>

int abs(int x) { return x < 0 ? -x : x; }

void printGrid(int **grid, int K) {
    for (int i = 0; i < K; i++) {
        for (int j = 0; j < K; j++) {
            printf("%d ", grid[i][j]);
        }
        printf("\n");
    }
}

int **constructGrid(int K) {
    int **grid = (int **)malloc(K * sizeof(int *));
    for (int i = 0; i < K; i++) {
        grid[i] = (int *)malloc(K * sizeof(int));
    }

    for (int i = 0; i < K; i++) {
        for (int j = 0; j < K; j++) {
            grid[i][j] = (i + j) % K + 1;
        }
    }

    return grid;
}

int main() {
    int T;
    scanf("%d", &T);

    for (int t = 0; t < T; t++) {
        int K;
        scanf("%d", &K);

        int **grid = constructGrid(K);
        printGrid(grid, K);

        for (int i = 0; i < K; i++) {
            free(grid[i]);
        }
        free(grid);
    }

    return 0;
}

