import java.util.Scanner;
public class Main {
    public static void printGrid(int[][] grid, int K) {
        for (int i = 0; i < K; i++) {
            for (int j = 0; j < K; j++) {
                System.out.print(grid[i][j] + " ");
            }
            System.out.println();
        }
    }

    public static int[][] constructGrid(int K) {
        int[][] grid = new int[K][K];

        for (int i = 0; i < K; i++) {
            for (int j = 0; j < K; j++) {
                grid[i][j] = (i + j) % K + 1;
            }
        }

        return grid;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();

        for (int t = 0; t < T; t++) {
            int K = scanner.nextInt();

            int[][] grid = constructGrid(K);
            printGrid(grid, K);
        }
    }
}

