const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function printGrid(grid, K) {
    for (let i = 0; i < K; i++) {
        let row = '';
        for (let j = 0; j < K; j++) {
            row += grid[i][j] + ' ';
        }
        console.log(row);
    }
}

function constructGrid(K) {
    let grid = [];
    for (let i = 0; i < K; i++) {
        let row = [];
        for (let j = 0; j < K; j++) {
            row.push((i + j) % K + 1);
        }
        grid.push(row);
    }
    return grid;
}

let T = parseInt(lines[idx++]);
for (let t = 0; t < T; t++) {
    let K = parseInt(lines[idx++]);
    let grid = constructGrid(K);
    printGrid(grid, K);
}
